// 입력 파싱 및 기본값 설정
const body = $input.first().json.body;
const query = (body.query || '').trim();
const type = (body.type || 'full').toLowerCase();

if (!query) {
  return [{ json: { error: true, message: '검색어(query)가 필요합니다.' } }];
}

const validTypes = ['law', 'precedent', 'interpretation', 'full'];
if (!validTypes.includes(type)) {
  return [{ json: { error: true, message: '유효한 type: law, precedent, interpretation, full' } }];
}

return [{ json: { error: false, query, type } }];

// 법령 검색 결과 XML 파싱 (단일)
const xml = $input.first().json.data || '';
const query = $('입력 검증').first().json.query;

function extractTag(str, tag) {
  const regex = new RegExp('<' + tag + '>(.*?)</' + tag + '>', 'gs');
  const matches = [];
  let m;
  while ((m = regex.exec(str)) !== null) {
    matches.push(m[1].trim());
  }
  return matches;
}

function extractLaws(xmlStr) {
  const items = xmlStr.split(/<법령>/).filter(s => s.trim());
  const results = [];
  for (const item of items) {
    const name = (extractTag(item, '법령명한글')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    if (!name) continue;
    const id = extractTag(item, '법령일련번호')[0] || '';
    const mst = extractTag(item, '법령MST')[0] || id;
    const lawType = extractTag(item, '법령구분명')[0] || '';
    const dept = (extractTag(item, '소관부처명')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    const date = extractTag(item, '시행일자')[0] || '';
    results.push({ name, id, mst, type: lawType, department: dept, effectiveDate: date });
  }
  return results;
}

const laws = extractLaws(xml);
return [{ json: {
  success: true,
  query,
  results: { laws, precedents: [], interpretations: [] },
  summary: '검색 결과: 법령 ' + laws.length + '건'
} }];

// 판례 검색 결과 XML 파싱 (단일)
const xml = $input.first().json.data || '';
const query = $('입력 검증').first().json.query;

function extractTag(str, tag) {
  const regex = new RegExp('<' + tag + '>(.*?)</' + tag + '>', 'gs');
