    const date = extractTag(item, '선고일자')[0] || '';
    const result = (extractTag(item, '판결유형')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    results.push({ name, id, caseNumber: caseNum, court, date, result });
  }
  return results;
}

const precedents = extractPrecs(xml);
return [{ json: {
