function extractExpcs(xmlStr) {
  const items = xmlStr.split(/<해석례>/).filter(s => s.trim());
  const results = [];
  for (const item of items) {
    const title = (extractTag(item, '제목')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    if (!title) continue;
    const id = extractTag(item, '해석례일련번호')[0] || '';
    const type = (extractTag(item, '해석례구분명')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    const org = (extractTag(item, '회신기관명')[0] || '').replace(/<!\[CDATA\[|\]\]>/g, '');
    const date = extractTag(item, '안건번호일자')[0] || '';
    results.push({ title, id, type, organization: org, date });
  }
  return results;
}

const interpretations = extractExpcs(xml);
return [{ json: {
  success: true,
  query,
  results: { laws: [], precedents: [], interpretations },
  summary: '검색 결과: 해석례 ' + interpretations.length + '건'
} }];

// 전체 검색: 법령 + 판례 + 해석례 3개 응답 병합
const query = $('입력 검증').first().json.query;

// 각 HTTP 노드에서 결과 가져오기
const lawXml = $('법령 검색 (전체)').first().json.data || '';
const precXml = $('판례 검색 (전체)').first().json.data || '';
const expcXml = $('해석례 검색 (전체)').first().json.data || '';

function extractTag(str, tag) {
  const regex = new RegExp('<' + tag + '>(.*?)</' + tag + '>', 'gs');
  const matches = [];
  let m;
  while ((m = regex.exec(str)) !== null) {
    matches.push(m[1].trim());
  }
  return matches;
}

function cleanCdata(s) {
  return (s || '').replace(/<!\[CDATA\[|\]\]>/g, '');
}

// 법령 파싱
function extractLaws(xmlStr) {
  const items = xmlStr.split(/<법령>/).filter(s => s.trim());
  const results = [];
  for (const item of items) {
    const name = cleanCdata(extractTag(item, '법령명한글')[0] || '');
    if (!name) continue;
    const id = extractTag(item, '법령일련번호')[0] || '';
    const mst = extractTag(item, '법령MST')[0] || id;
    const lawType = extractTag(item, '법령구분명')[0] || '';
    const dept = cleanCdata(extractTag(item, '소관부처명')[0] || '');
    const date = extractTag(item, '시행일자')[0] || '';
    results.push({ name, id, mst, type: lawType, department: dept, effectiveDate: date });
  }
  return results;
}

// 판례 파싱
function extractPrecs(xmlStr) {
  const items = xmlStr.split(/<판례>/).filter(s => s.trim());
  const results = [];
  for (const item of items) {
    const name = cleanCdata(extractTag(item, '사건명')[0] || '');
    if (!name) continue;
    const id = extractTag(item, '판례일련번호')[0] || '';
    const caseNum = cleanCdata(extractTag(item, '사건번호')[0] || '');
    const court = cleanCdata(extractTag(item, '법원명')[0] || '');
    const date = extractTag(item, '선고일자')[0] || '';
    const result = cleanCdata(extractTag(item, '판결유형')[0] || '');
    results.push({ name, id, caseNumber: caseNum, court, date, result });
  }
  return results;
}

// 해석례 파싱
function extractExpcs(xmlStr) {
  const items = xmlStr.split(/<해석례>/).filter(s => s.trim());
  const results = [];
  for (const item of items) {
    const title = cleanCdata(extractTag(item, '제목')[0] || '');
    if (!title) continue;
    const id = extractTag(item, '해석례일련번호')[0] || '';
    const type = cleanCdata(extractTag(item, '해석례구분명')[0] || '');
    const org = cleanCdata(extractTag(item, '회신기관명')[0] || '');
    const date = extractTag(item, '안건번호일자')[0] || '';
    results.push({ title, id, type, organization: org, date });
  }
  return results;
}

const laws = extractLaws(lawXml);
const precedents = extractPrecs(precXml);
const interpretations = extractExpcs(expcXml);

const parts = [];
if (laws.length > 0) parts.push('법령 ' + laws.length + '건');
if (precedents.length > 0) parts.push('판례 ' + precedents.length + '건');
if (interpretations.length > 0) parts.push('해석례 ' + interpretations.length + '건');
const summaryText = parts.length > 0 ? '검색 결과: ' + parts.join(', ') : '검색 결과 없음';

return [{ json: {
  success: true,
  query,
  results: { laws, precedents, interpretations },
  summary: summaryText
} }];
